import{_ as e,o as a,c as n,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Snap Overview","description":"","frontmatter":{"title":"Snap Overview","slug":"snap"},"headers":[],"relativePath":"marketer-hub/snap.md","filePath":"marketer-hub/snap.md"}'),r={name:"marketer-hub/snap.md"};function d(i,t,s,c,l,p){return a(),n("div",null,[...t[0]||(t[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch offers advanced ad attribution insights with integration for <a href="https://forbusiness.snapchat.com/ad-products" target="_blank" rel="noreferrer">Snap</a>. Using Snap&#39;s self-attribution network (SAN) data and Branch&#39;s mobile measurement system, you can see how many installs and conversion events were attributed to Snap, allowing you to make informed decisions with your advertising dollars.</p><p>Branch and Snap supports mobile app conversion attribution for the following campaign objective and goal-based bidding objectives:</p><table tabindex="0"><thead><tr><th>Campaign Objective</th><th>Goal-Based Bidding Objective</th></tr></thead><tbody><tr><td>Drive Traffic to App</td><td>Acquisition: - Swipe Up - Install - App Purchase - Add to Cart - App Sign Up</td></tr><tr><td>Drive Traffic to App</td><td>Re-Engagement: - Swipe Up - App Open (Re-Engagement) - App Purchase (Re-Engagement)</td></tr></tbody></table><h4 id="additional-campaign-identifiers" tabindex="-1">Additional Campaign Identifiers <a class="header-anchor" href="#additional-campaign-identifiers" aria-label="Permalink to &quot;Additional Campaign Identifiers&quot;">​</a></h4><div class="info custom-block"><p class="custom-block-title">Snap Advanced Conversions</p><p>To utilize additional campaign identifiers, <a href="./snap-advanced-conversions.html">Snap Advanced Conversions</a> need to be <strong>enabled</strong>.</p></div><p>Snap appends a Click ID, known as the <code>ScCid</code> parameter, to deep links on iOS and Android devices for opt-in and opt-out users. Branch then parses the <code>ScCid</code> from events and provides them to Snap for attribution and campaign optimization.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before you begin, be sure the following is confirmed.</p><ul><li>First, the Branch SDK must be integrated into your app, for both iOS and Android.</li><li>You must also collect the IDFA on iOS, or the AAID on Android. For specifics, refer to the set up guide for <a href="./ios-sdk-overview.html">iOS</a> and <a href="./android-sdk-overview.html">Android</a> respectively.</li><li>Make sure to track all necessary events through the SDKs.</li></ul><p>In order to enable Snap, you need to have completed the following:</p><ol><li><p>Created a <a href="https://dashboard.branch.io/?_gl=1*15zk0r2*_ga*MTM3OTcwNTU1OC4xNjkzNTg5NjI0*_ga_KSDD8Y11CT*MTY5ODQxNzkzOS4xMi4xLjE2OTg0MjYyOTYuNjAuMC4w" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Enabled Ads for your Branch account.</p><ol><li>Contact your Branch account manager or visit <a href="https://branch.io/pricing" target="_blank" rel="noreferrer">https://branch.io/pricing</a></li></ol></li><li><p>Implemented the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>)</p><ol><li><a href="./track-branch-events.html">Track events</a></li></ol></li><li><p>Admin access to your Snap account.</p></li></ol><h2 id="enable-snap" tabindex="-1">Enable Snap <a class="header-anchor" href="#enable-snap" aria-label="Permalink to &quot;Enable Snap&quot;">​</a></h2><h3 id="_1-connect-snap-in-branch" tabindex="-1">1. Connect Snap in Branch <a class="header-anchor" href="#_1-connect-snap-in-branch" aria-label="Permalink to &quot;1. Connect Snap in Branch&quot;">​</a></h3><p>In the Branch Dashboard under <strong>Ads &gt;</strong> <a href="https://branch.dashboard.branch.io/ads/partner-management/" target="_blank" rel="noreferrer"><strong>Partner Management</strong></a>, find/search for Google AdWords. If you&#39;re already logged into the Branch Dashboard, you can also click <a href="https://branch.dashboard.branch.io/ads/partner-management/a_snap?tab=settings" target="_blank" rel="noreferrer">here</a> to go there directly.</p><p>Click the <strong>Log In With Snapchat</strong> button to authenticate with your Snap account.</p><p>After connecting, Snap should be connected to Branch!</p><h3 id="_2-add-snap-app-id" tabindex="-1">2. Add Snap App ID <a class="header-anchor" href="#_2-add-snap-app-id" aria-label="Permalink to &quot;2. Add Snap App ID&quot;">​</a></h3><p>Enter your <strong>Snap App ID</strong>. To use different IDs for your Android and iOS apps, check the <strong>Use different iOS and Android IDs</strong> box. To add multiple Snap App IDs, separate each value with a comma.</p><div class="info custom-block"><p class="custom-block-title">Connecting Multiple Accounts</p><p>All SANs - including Snap - accept multiple accounts. However, only a single Branch user can authenticate the integration. This means that the single user must have access to all of the accounts you wish to connect.</p></div><p>Click the <strong>Save</strong> button, and you can verify all of your Snap information:</p><h2 id="viewing-snap-data" tabindex="-1">Viewing Snap Data <a class="header-anchor" href="#viewing-snap-data" aria-label="Permalink to &quot;Viewing Snap Data&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Data Purge</p><ul><li>Branch will purge last-attributed data after 60 days.</li></ul></div><h3 id="view-attribution-on-dashboard" tabindex="-1">View Attribution on Dashboard <a class="header-anchor" href="#view-attribution-on-dashboard" aria-label="Permalink to &quot;View Attribution on Dashboard&quot;">​</a></h3><p>All attribution can be visible on the <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch dashboard summary page</a>. All installs and opens registered from this channel will automatically be tagged with <code>Ad Partner</code>: <code>Snap</code>. Other analytics tags will reflect the campaign, ad squad and ad names you set up in the Snap Ads dashboard.</p><p>Note that these stats are <strong>limited to the date range</strong> at the top of the page. You can expand the range if you&#39;d like.</p><h3 id="data-mapping" tabindex="-1">Data Mapping <a class="header-anchor" href="#data-mapping" aria-label="Permalink to &quot;Data Mapping&quot;">​</a></h3><h4 id="event-names" tabindex="-1">Event Names <a class="header-anchor" href="#event-names" aria-label="Permalink to &quot;Event Names&quot;">​</a></h4><p>Branch supports sending <a href="./track-branch-events.html">Standard and Custom Events</a> to Snap.</p><p>Below are the mappings for Branch events to Snap events.</p><table tabindex="0"><thead><tr><th>Branch Event Name</th><th>Snap Event Name</th><th>Sent by Default</th></tr></thead><tbody><tr><td><code>INSTALL</code></td><td><code>APP_INSTALL</code></td><td>Yes</td></tr><tr><td><code>VIEW_ITEM</code></td><td><code>VIEW_CONTENT</code></td><td>Yes</td></tr><tr><td><code>ADD_TO_CART</code></td><td><code>ADD_CART</code></td><td>Yes</td></tr><tr><td><code>INITIATE_PURCHASE</code></td><td><code>START_CHECKOUT</code></td><td>Yes</td></tr><tr><td><code>PURCHASE</code></td><td><code>PURCHASE</code></td><td>Yes</td></tr><tr><td><code>ADD_PAYMENT_INFO</code></td><td><code>ADD_BILLING</code></td><td>Yes</td></tr><tr><td><code>COMPLETE_REGISTRATION</code></td><td><code>SIGN_UP</code></td><td>Yes</td></tr><tr><td><code>SEARCH</code></td><td><code>SEARCH</code></td><td>Yes</td></tr><tr><td><code>ACHIEVE_LEVEL</code></td><td><code>LEVEL_COMPLETE</code></td><td>Yes</td></tr><tr><td><code>OPEN / REINSTALL</code></td><td><code>APP_OPEN</code></td><td>Yes</td></tr><tr><td><code>SUBSCRIBE</code></td><td><code>SUBSCRIBE</code></td><td>Yes</td></tr><tr><td><code>CLICK_AD</code></td><td><code>AD_CLICK</code></td><td>Yes</td></tr><tr><td><code>VIEW_AD</code></td><td><code>AD_VIEW</code></td><td>Yes</td></tr><tr><td><code>COMPLETE_TUTORIAL</code></td><td><code>COMPLETE_TUTORIAL</code></td><td>Yes</td></tr><tr><td><code>INVITE</code></td><td><code>INVITE</code></td><td>Yes</td></tr><tr><td><code>LOGIN</code></td><td><code>LOGIN</code></td><td>Yes</td></tr><tr><td><code>SHARE</code></td><td><code>SHARE</code></td><td>Yes</td></tr><tr><td><code>RESERVE</code></td><td><code>RESERVE</code></td><td>Yes</td></tr><tr><td><code>UNLOCK_ACHIEVEMENT</code></td><td><code>ACHIEVEMENT_UNLOCKED</code></td><td>Yes</td></tr><tr><td><code>ADD_TO_WISHLIST</code></td><td><code>ADD_TO_WISHLIST</code></td><td>Yes</td></tr><tr><td><code>SPEND_CREDITS</code></td><td><code>SPENT_CREDITS</code></td><td>Yes</td></tr><tr><td><code>RATE</code></td><td><code>RATE</code></td><td>Yes</td></tr><tr><td><code>START_TRIAL</code></td><td><code>START_TRIAL</code></td><td>Yes</td></tr><tr><td><code>VIEW_ITEMS</code></td><td><code>LIST_VIEW</code></td><td>Yes</td></tr><tr><td><a href="./track-branch-events.html#track-custom-events">Custom</a> Branch Event</td><td><code>SAVE</code></td><td>No</td></tr><tr><td><a href="./track-branch-events.html#track-custom-events">Custom</a> Branch Event</td><td><code>PAGE_VIEW</code></td><td>No</td></tr></tbody></table><p>Snap also allows 5 slots for custom events. To use these slots, you can create a Branch <a href="./track-branch-events.html">Event</a> (either Standard or Custom), and that will get mapped to a Snap event that begins with <code>CUSTOM_EVENT_...</code>.</p><table tabindex="0"><thead><tr><th>Branch Event</th><th>Snap Event Name</th><th>Sent by Default</th></tr></thead><tbody><tr><td>Branch Event (Standard or Custom)</td><td><code>CUSTOM_EVENT_1</code></td><td>No</td></tr><tr><td>Branch Event (Standard or Custom)</td><td><code>CUSTOM_EVENT_2</code></td><td>No</td></tr><tr><td>Branch Event (Standard or Custom)</td><td><code>CUSTOM_EVENT_3</code></td><td>No</td></tr><tr><td>Branch Event (Standard or Custom)</td><td><code>CUSTOM_EVENT_4</code></td><td>No</td></tr><tr><td>Branch Event (Standard or Custom)</td><td><code>CUSTOM_EVENT_5</code></td><td>No</td></tr></tbody></table><h4 id="campaign-data" tabindex="-1">Campaign Data <a class="header-anchor" href="#campaign-data" aria-label="Permalink to &quot;Campaign Data&quot;">​</a></h4><p>Branch maps the following data fields from Snap to Branch.</p><table tabindex="0"><thead><tr><th>Branch Data</th><th>Snap Data</th><th>Parameter in Deep Link URL</th></tr></thead><tbody><tr><td><code>~campaign</code></td><td><code>campaign_name</code></td><td><code>cname</code></td></tr><tr><td><code>~campaign_id</code></td><td><code>campaign_id</code></td><td><code>cid</code></td></tr><tr><td><code>~ad_set_name</code></td><td><code>ad_squad_name</code></td><td><code>adsetname</code></td></tr><tr><td><code>~ad_set_id</code></td><td><code>ad_squad_id</code></td><td><code>adsetid</code></td></tr><tr><td><code>~ad_name</code></td><td><code>ad_name</code></td><td><code>adname</code></td></tr><tr><td><code>~ad_id</code></td><td><code>ad_id</code></td><td><code>adid</code></td></tr><tr><td><code>~ad_account_id</code></td><td><code>ad_account_id</code></td><td><code>adacctid</code></td></tr></tbody></table><h4 id="metadata" tabindex="-1">Metadata <a class="header-anchor" href="#metadata" aria-label="Permalink to &quot;Metadata&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Branch metadata</th><th>Snap Metadata</th><th>Description</th></tr></thead><tbody><tr><td>SKU (list of)</td><td><code>item_ids</code></td><td>International Article Number (EAN) when applicable, or other product or category identifier.</td></tr><tr><td><code>Quantity</code></td><td><code>number_items</code></td><td>Number of items.</td></tr><tr><td><code>revenue</code></td><td><code>price</code></td><td>Monetary value of the conversion event in float format. Please do not include currency symbols or commas as part of the value. (ex. single value: price=34.24, multiple values: price=99.43,45.34;34.27)</td></tr><tr><td><code>currency_code</code></td><td><code>currency</code></td><td>Currency in standard ISO 4217 code (ex. EUR, USD, JPY). Required if price is included.</td></tr><tr><td><code>transactionID</code></td><td><code>transaction_id</code></td><td>Transaction ID.</td></tr><tr><td><code>searchQuery</code></td><td><code>search_string</code></td><td>The text string that was searched.</td></tr><tr><td><code>custom_data.level</code></td><td><code>level</code></td><td>Level in the game.</td></tr></tbody></table><h4 id="cost-data" tabindex="-1">Cost Data <a class="header-anchor" href="#cost-data" aria-label="Permalink to &quot;Cost Data&quot;">​</a></h4><ul><li>To view the cost metrics Branch provides, please see <a href="./what-is-a-self-attributing-network.html#san-cost-data">SAN Cost Data</a>.</li><li>If you&#39;re seeing discrepancies, please see <a href="./common-sources-of-san-reporting-discrepancies.html">Common Sources of SAN Reporting Discrepancies</a>.</li></ul><h3 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h3><h4 id="discrepancies" tabindex="-1">Discrepancies <a class="header-anchor" href="#discrepancies" aria-label="Permalink to &quot;Discrepancies&quot;">​</a></h4><ul><li><p>Snap Ads Manager time zones are set at the time your ad account is created. You can see your Snap time zone in your Snap Ad Account Settings, but you cannot change it. You can change your Branch dashboard time zone in <a href="https://dashboard.branch.io/account-settings/app" target="_blank" rel="noreferrer">Account Settings</a> to match.</p></li><li><p>Verify your Snap attribution windows match your Branch attribution windows. Ask your Snap account manager for your attribution windows. Your Branch windows are visible either in Link Settings (global windows) or in the <a href="https://dashboard.branch.io/ads/partner-management/a_snap?tab=attribution_windows" target="_blank" rel="noreferrer">Attribution Windows</a> section of the Snap entry in Ads Partner Manager. Snap windows can be configured under &quot;Customize Columns&quot; in the Snap UI.</p></li><li><p>When deep linking, create a link via the Branch dashboard. If you are running an app campaign, please ensure your link has <code>%24deeplink_no_attribution=true</code> as a query parameter to remove that link&#39;s ability to claim attribution, otherwise the link may claim attribution over the SAN claim. The link will still deep link.</p></li><li><p>Snap&#39;s reporting API does not provide any &quot;compare by&quot; functionality outside of the ads analytics tags. So, you cannot compare Snap click + impression data by platform, OS or country, for example.</p></li></ul><h4 id="exporting-snap-data" tabindex="-1">Exporting Snap Data <a class="header-anchor" href="#exporting-snap-data" aria-label="Permalink to &quot;Exporting Snap Data&quot;">​</a></h4><div class="warning custom-block"><p class="custom-block-title">Restrictions on Raw Data Exports</p><p>Snap is introducing upcoming restrictions for User-Level Raw Data Exports (‘Log-Level Restrictions’) that will impact all third party MMP platforms that work with Snap.</p><p>Branch customers will experience the effects of this change starting <strong>January 3rd, 2024</strong>.</p><p><strong>What does this change look like within Branch?</strong></p><p>For Branch customers, Snap&#39;s privacy-enhancing reporting changes will mean:</p><ul><li><p>Restrictions to log-level view-through conversion data, limiting certain fields such as campaign-level data and timestamp. This impacts the following Branch products:</p><ul><li>The Daily Exports, Custom Exports, and Scheduled Log Exports APIs</li><li>Third-party Data Integrations</li><li>Webhooks</li><li>Ad Partner Postbacks</li></ul></li><li><p>Advertisers can still see Snap as the media source for view-through conversions; however, campaign-level breakdowns will be unavailable for raw data exports.</p></li><li><p>Campaign-level aggregate data will continue to be provided through the Branch Dashboard and aggregate-level APIs, as well as through Snap’s own reporting interfaces and API.</p></li></ul><p><strong>How will Branch de-identify data?</strong></p><p>For attribution reports that include view-through engagement, Branch will make the following adjustments to de-identify such data:</p><ul><li><p>The Media Source (PID) will be Snapchat, and will not otherwise be obfuscated or restricted.</p></li><li><p>Snap campaign information will be removed, specifically:</p><ul><li>Ad Account ID</li><li>Campaign ID</li><li>Ad Squad ID</li><li>Ad ID (and associated names)</li></ul></li><li><p>Attributed touch time will be reported as date only (dd/mm/yyyy)</p></li><li><p>Deep link URI information will be removed</p></li></ul><p><strong>Restricted Parameters</strong></p><table tabindex="0"><thead><tr><th>Snap Parameter</th><th>Branch Parameter</th></tr></thead><tbody><tr><td>ad_account_id</td><td>~advertising_account_id</td></tr><tr><td>ad_id</td><td>~ad_id</td></tr><tr><td>ad_name</td><td>~ad_name</td></tr><tr><td>country</td><td>~country_or_region</td></tr><tr><td>request_id</td><td>N/A</td></tr><tr><td>snap_channel</td><td>~secondary_publisher</td></tr><tr><td>deep_link_url</td><td>external_intent_uri, universal_link_url, android_app_link_url</td></tr></tbody></table></div><p>You can see analytics on impressions, clicks, installs, opens and conversion events on various pages of the Branch Dashboard.</p><p>We cannot send device-level Snap attribution data to third parties. Thus, we cannot send events attributed to Snap via Data Integrations. Please instead consider analyzing this data in-house (using Webhooks, the Daily Export API, or CSV Exports), or using the Branch Dashboard for all of your analytics and attribution needs.</p><h2 id="snap-skadnetwork" tabindex="-1">Snap SKAdNetwork <a class="header-anchor" href="#snap-skadnetwork" aria-label="Permalink to &quot;Snap SKAdNetwork&quot;">​</a></h2><p>Branch and Snap are integrated for SKAdNetwork! For customers using the Branch SDK, Branch will provide Snap your conversion value mapping for campaign optimization.</p><p>Snap requires that Snap event names be used in order to make use of that mapping. In order to accomodate, Branch will send the Snap event name for your conversion values as long as you have the correct events mapped under Partner Management --&gt; Event Config.</p><p>To check if we will send Snap event names for your conversion value mapping:</p><ol><li><p>Go to Ads --&gt; Partner Management --&gt; Snap --&gt; Event Config</p></li><li><p>Add Branch MMP to Snap. Select Branch from the &#39;Please share postbacks with this MMP&#39; drop down field in the <strong>Snap App Details</strong></p></li><li><p>Ensure that the Branch events you are using for Conversion Values are mapped to corresponding Snap event names</p></li></ol><h2 id="advanced" tabindex="-1">Advanced <a class="header-anchor" href="#advanced" aria-label="Permalink to &quot;Advanced&quot;">​</a></h2><h3 id="snap-app-id" tabindex="-1">Snap App ID <a class="header-anchor" href="#snap-app-id" aria-label="Permalink to &quot;Snap App ID&quot;">​</a></h3><p>Snap App IDs are generated by an advertiser in Snap’s Business Manager or when they register their app for Snap at <a href="https://kit.snapchat.com/" target="_blank" rel="noreferrer">https://kit.snapchat.com/</a>and tied to the advertiser’s organization ID. Snap App IDs are associated to an advertiser’s organization in Snap’s ad platform. If the Snap App ID is generated in Snap Kit, it will need to be linked to their organization in Business Manager.</p><p>Advertisers will only be able to build mobile app custom audiences from their mobile measurement events inside Snap’s ad platform from postback events that have their Snap App ID(s).</p><p>Learn more about the <a href="https://businesshelp.snapchat.com/en-US/article/snap-app-id" target="_blank" rel="noreferrer">Snap App ID</a>.</p><h3 id="snap-audience-network" tabindex="-1">Snap Audience Network <a class="header-anchor" href="#snap-audience-network" aria-label="Permalink to &quot;Snap Audience Network&quot;">​</a></h3><p>Snap Audience Network (SDK and RTB) is a network where advertisers can expand the reach of their campaigns beyond Snapchat. Conversion attribution will work the same as Snapchat conversion attribution and advertisers will have the ability to run a single campaign across both Snapchat and<br> the Snap Audience Network (SAN).</p><p>Learn more about <a href="https://businesshelp.snapchat.com/en-US/a/custom-audiences" target="_blank" rel="noreferrer">Snap Custom Audiences</a>.</p><h3 id="deep-link-support-for-snap-campaigns" tabindex="-1">Deep link support for Snap Campaigns <a class="header-anchor" href="#deep-link-support-for-snap-campaigns" aria-label="Permalink to &quot;Deep link support for Snap Campaigns&quot;">​</a></h3><p>Branch Links can be used for click &amp; impression tracking, however, you cannot leverage Branch Links directly in the Deeplink field. Snap currently restrics any Universal Link or App Link or MMP redirect link in their paid media campaigns (<a href="https://businesshelp.snapchat.com/s/article/deeplink-specs?language=en_US#:~:text=Deep%20Link%20Specifications" target="_blank" rel="noreferrer">Snap documentation</a>). For SAN deferred deep linking support go <a href="./san-deferred-deep-linking.html">here</a>.</p><p>Your app needs to be able to read the Deep link URI <strong>AND</strong> any additional data necessary for routing.</p><ol><li><p>Ensure that your app is set up to read custom URI scheme key:value pairs for the purposes of deep link routing</p></li><li><p>Fetch your URI scheme from the Branch app configuration.</p></li><li><p>Combine your URI scheme with your required key:value pair (e.g. yourBranchappscheme://yourKeyValue).</p></li><li><p>Set up your Snap campaign, selecting <strong>Drive Traffic to App</strong>.</p></li><li><p>On the <strong>Build Your Ads</strong> page:</p><ol><li>Paste your Branch URI scheme into the <strong>DEEPLINK URI</strong> field.</li><li>Select <strong>Web Site</strong> as the <strong>FALLBACK TYPE</strong> and add web URL to ensure routing for non-app users.</li></ol></li><li><p>Finish building your Snap campaign.</p></li></ol><div class="warning custom-block"><p class="custom-block-title">Web Site as Fallback Required for Deferred Deep Linking</p><p>Please ensure you choose <strong>Web Site</strong> as the <strong>FALLBACK TYPE</strong> and inserting the same Branch Link into the provided field. If you choose <strong>App Install</strong> as the <code>FALLBACK TYPE</code>, users not properly routed will be sent to the App Store without the Branch Link and deferred deep linking will not occur.</p></div><div class="info custom-block"><p class="custom-block-title">Agency-Managed Campaigns</p><ul><li>If an Agency manages your Snap campaigns, please see <a href="./what-is-a-self-attributing-network.html#agency-managed-san-campaigns">Agency-managed SAN Campaigns</a>.</li></ul></div>',66)])])}const m=e(r,[["render",d]]);export{u as __pageData,m as default};
